from pathlib import Path
files=['src/domain/scanner.rs','src/services/scanner.rs','src/app/scanner_controller.rs','src/workers/events.rs','src/workers/mod.rs','src/main.rs','ui/scanner_tab.slint','ui/main.slint']
for f in files:
    p=Path(f)
    print(f'## {f} ({p.stat().st_size} bytes)')
    text=p.read_text(encoding='utf-8')
    for term in ['struct Scanner','enum Scanner','AutoFix','AUTO_FIX','ScannerAction','WorkerEvent','Scan','callback','fix']:
        matches=[(i+1,l.strip()) for i,l in enumerate(text.splitlines()) if term in l]
        if matches:
            print(f'  {term}: {len(matches)}')
            for i,l in matches[:12]: print(f'    {i}: {l[:180]}')
    print()

