        "problem-overrides" => Some(ScannerCategoryKind::ProblemOverrides),
        "race-subgraphs" => Some(ScannerCategoryKind::RaceSubgraphs),
        _ => None,
    }
}

fn i32_to_usize(value: i32) -> Option<usize> {
    if value < 0 {
        None
    } else {
        Some(value as usize)
    }
}

